var gameState = "start";

var blueScore = 0;
var redScore = 0;

// FIELD
var field = createSprite(200,200);
field.setAnimation("field");

// GOALS
var goalBottom = createSprite(230,380);
goalBottom.setAnimation("goal");
goalBottom.scale = 2;

var goalTop = createSprite(200,20);
goalTop.setAnimation("goal");
goalTop.rotation = 180;
goalTop.scale = 2;

// BALL
var ball = createSprite(200,200);
ball.setAnimation("ball");
ball.scale = 0.10;

// PLAYERS
var bluePlayer = createSprite(160,380);
bluePlayer.setAnimation("kid1");
bluePlayer.scale = 0.25;

var redPlayer = createSprite(200,20);
redPlayer.setAnimation("kid2");
redPlayer.rotation = 180;
redPlayer.scale = 0.2;


// DRAW LOOP
function draw() {

  // START SCREEN
  if (gameState == "start") {

    background("black");

    fill("white");
    textSize(30);
    text("SOCCER GAME",110,170);

    textSize(18);
    text("Blue: Arrow Keys",120,210);
    text("Red: WASD",150,235);
    text("Press SPACE to Start",110,270);

    if (keyDown("space")) {
      gameState = "play";
    }
  }


  // GAME PLAY
  else if (gameState == "play") {

    // BLUE PLAYER
    if (keyDown("up")) bluePlayer.y -= 3;
    if (keyDown("down")) bluePlayer.y += 3;
    if (keyDown("left")) bluePlayer.x -= 4;
    if (keyDown("right")) bluePlayer.x += 4;

    // RED PLAYER
    if (keyDown("w")) redPlayer.y -= 3;
    if (keyDown("s")) redPlayer.y += 3;
    if (keyDown("a")) redPlayer.x -= 4;
    if (keyDown("d")) redPlayer.x += 4;

    // BALL KICK
    if (ball.isTouching(bluePlayer)) {
      ball.velocityX = (ball.x-bluePlayer.x)*0.25;
      ball.velocityY = (ball.y-bluePlayer.y)*0.25;
    }

    if (ball.isTouching(redPlayer)) {
      ball.velocityX = (ball.x-redPlayer.x)*0.25;
      ball.velocityY = (ball.y-redPlayer.y)*0.25;
    }

    // GOAL FOR BLUE
    if (ball.isTouching(goalBottom)) {

      blueScore++;

      ball.x = 200;
      ball.y = 200;
      ball.velocityX = 0;
      ball.velocityY = 0;
    }

    // GOAL FOR RED
    if (ball.isTouching(goalTop)) {

      redScore++;

      ball.x = 200;
      ball.y = 200;
      ball.velocityX = 0;
      ball.velocityY = 0;
    }

    // WIN CONDITION
    if (blueScore >= 5) {
      gameState = "blueWin";
    }

    if (redScore >= 5) {
      gameState = "redWin";
    }

    drawSprites();

    fill("blue");
    textSize(20);
    text("Blue: "+blueScore,20,30);

    fill("red");
    text("Red: "+redScore,320,30);
  }


  // BLUE WIN SCREEN
  else if (gameState == "blueWin") {

    background("black");

    fill("blue");
    textSize(40);
    text("BLUE TEAM WINS!",60,200);

    fill("white");
    textSize(20);
    text("Press R to Restart",120,250);

    if (keyDown("r")) {

      blueScore = 0;
      redScore = 0;

      ball.x = 200;
      ball.y = 200;
      ball.velocityX = 0;
      ball.velocityY = 0;

      gameState = "start";
    }
  }


  // RED WIN SCREEN
  else if (gameState == "redWin") {

    background("black");

    fill("red");
    textSize(40);
    text("RED TEAM WINS!",70,200);

    fill("white");
    textSize(20);
    text("Press R to Restart",120,250);

    if (keyDown("r")) {

      blueScore = 0;
      redScore = 0;

      ball.x = 200;
      ball.y = 200;
      ball.velocityX = 0;
      ball.velocityY = 0;

      gameState = "start";
    }
  }

}
